create or replace view public.scholarship_attributions with (security_invoker=false) as select o.scholarship_id,s.name as source_name,o.source_page_url,o.last_seen_at from public.source_observations o join public.external_sources s on s.id=o.source_id join public.external_scholarships e on e.id=o.scholarship_id where e.published_at is not null and e.archived_at is null;
revoke all on public.scholarship_attributions from public;
grant select on public.scholarship_attributions to anon,authenticated;
create table if not exists public.scholarship_change_history(id bigint generated always as identity primary key,scholarship_id uuid not null references public.external_scholarships on delete cascade,changed_fields jsonb not null,created_at timestamptz not null default now());
alter table public.scholarship_change_history enable row level security;
create policy "scholarship_change_staff_read" on public.scholarship_change_history for select to authenticated using(public.has_role('program_admin') or public.has_role('super_admin'));
create or replace function public.record_scholarship_change() returns trigger language plpgsql security definer set search_path=public as $$ declare changes jsonb:='{}'::jsonb; begin if old.title is distinct from new.title then changes:=changes||jsonb_build_object('title',jsonb_build_object('from',old.title,'to',new.title));end if;if old.amount_text is distinct from new.amount_text then changes:=changes||jsonb_build_object('amount_text',jsonb_build_object('from',old.amount_text,'to',new.amount_text));end if;if old.deadline is distinct from new.deadline or old.deadline_kind is distinct from new.deadline_kind then changes:=changes||jsonb_build_object('deadline',jsonb_build_object('from',old.deadline,'to',new.deadline,'kind',new.deadline_kind));end if;if old.original_url is distinct from new.original_url then changes:=changes||jsonb_build_object('original_url','changed');end if;if changes<>'{}'::jsonb then insert into public.scholarship_change_history(scholarship_id,changed_fields) values(new.id,changes);end if;return new;end $$;
drop trigger if exists record_scholarship_change on public.external_scholarships;
create trigger record_scholarship_change after update on public.external_scholarships for each row execute procedure public.record_scholarship_change();
create or replace function public.queue_due_scholarship_reminders(p_limit int default 100) returns int language plpgsql security definer set search_path=public as $$ declare item record;queued int:=0;begin for item in select r.user_id,r.scholarship_id,p.primary_email,coalesce(nullif(p.preferred_name,''),nullif(p.legal_name,''),'Applicant') as applicant_name,e.title,e.deadline,e.slug from public.scholarship_reminders r join public.profiles p on p.id=r.user_id join public.external_scholarships e on e.id=r.scholarship_id where r.sent_at is null and r.remind_at<=now() and e.archived_at is null and not exists(select 1 from public.email_suppressions s where lower(s.email::text)=lower(p.primary_email::text)) order by r.remind_at for update of r skip locked limit least(greatest(p_limit,1),500) loop insert into public.messages(recipient,idempotency_key,status,payload_private,template_key) values(item.primary_email,'scholarship-reminder:'||item.user_id::text||':'||item.scholarship_id::text,'queued',jsonb_build_object('name',item.applicant_name,'title',item.title,'deadline',item.deadline,'scholarship_path','/scholarships/'||item.slug),'scholarship_reminder') on conflict(idempotency_key) do nothing;update public.scholarship_reminders set sent_at=now() where user_id=item.user_id and scholarship_id=item.scholarship_id;queued:=queued+1;end loop;return queued;end $$;
revoke all on function public.queue_due_scholarship_reminders(int) from public,anon,authenticated;
grant execute on function public.queue_due_scholarship_reminders(int) to service_role;
